}

function hex_to_bytes(text, expected_size)
{
    if (typeof text !== "string" || text.length !== expected_size * 2 || !/^[0-9a-fA-F]+$/.test(text))
    {
        throw new Error("Invalid hex string");
    }

    const bytes = new Uint8Array(expected_size);
