    size_t len = strlen(line);
    while (len > 3)
    {
        line[len - 3] = '.';
        line[len - 2] = '.';
        line[len - 1] = '.';
        line[len] = '\0';
        if (thefly_display.textWidth(line) <= width)
        {
            thefly_display.drawString(line, x, y);
            return;
        }
        line[len - 3] = '\0';
        --len;
    }

    thefly_display.drawString("...", x, y);
}

void format_mac_hyphen(const uint8_t mac[6], char* out, size_t out_size)
